type TDSettings={mode:"真心话"|"大冒险"|"随机";difficulty:TDDifficulty;age:"全年龄"|"16+"|"18+";alcohol:boolean;couple:boolean;touch:boolean;prank:boolean;autoRandom:boolean;blindBox:boolean};
type TDQuestion={id:string;mode:TDMode;text:string;difficulty:TDDifficulty;age:0|16|18;alcohol?:boolean;couple?:boolean;touch?:boolean;prank?:boolean;target?:boolean};
const TD_AVATARS=["🐱","😸","😻","😼","😺","🙀"];
const TD_QUESTIONS:TDQuestion[]=truthQuestionSeeds as TDQuestion[];
type BoxRarity="普通"|"稀有"|"史诗"|"传说"|"神话";
type BoxEffect="redraw"|"skip"|"immune"|"shield"|"transfer"|"together"|"designate"|"extra"|"all"|"empty"|"collectible"|"photo"|"no-items"|"lose-item"|"no-immune"|"gift-item"|"sealed"|"double-bad"|"chain"|"force-truth"|"force-dare"|"rarity-curse"|"haunt"|"demon"|"shield-curse"|"chaos"|"capacity"|"guardian"|"dice"|"coin"|"jackpot"|"holy-shield"|"copy"|"steal";
type BoxItem={id:string;name:string;icon:string;rarity:BoxRarity;description:string;effect:BoxEffect;negative?:boolean;weight:number};
type BoxStatuses={noItems:number;noImmune:number;sealed:number;doubleBad:number;chain:number;forceTruth:number;forceDare:number;rarityCurse:number;haunt:number;demon:number;shieldCurse:number;guardian:number;shield:number;holyShield:number;mirror:number};
